#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[10005];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        // Tokenize using space as delimiter; strtok skips consecutive delimiters
        char *words[5005];
        int cnt = 0;
        char *token = strtok(line, " ");
        while (token) {
            words[cnt++] = token;
            token = strtok(NULL, " ");
        }
        // Output in reverse order
        for (int i = cnt - 1; i >= 0; --i) {
            printf("%s", words[i]);
            if (i) printf(" ");
        }
        if (tc < T - 1) printf("\n");
    }
    return 0;
}

