        string s;
        getline(cin, s);
        stringstream ss(s);
        vector<string> words;
        string w;
        while (ss >> w) words.push_back(w);
        for (int i = (int)words.size() - 1; i >= 0; --i) {
            cout << words[i];
            if (i) cout << ' ';
        }
        if (tc < T - 1) cout << '\n';
    }
    return 0;
}

